import TomSelect from"../../tom-select.js";import{KEY_RETURN}from"../../constants.js";import{getDom,setAttr}from"../../vanilla.js";import{addEvent}from"../../utils.js";TomSelect.define("dropdown_input",function(){var t=this,e=t.settings.controlInput||'<input type="text" autocomplete="off" class="dropdown-input" />';e=getDom(e),t.settings.placeholder&&setAttr(e,{placeholder:t.settings.placeholder}),t.settings.controlInput=e,t.settings.shouldOpen=!0,t.hook("after","setup",()=>{setAttr(t.wrapper,{tabindex:t.input.disabled?"-1":t.tabIndex}),addEvent(t.wrapper,"keypress",e=>{if(!t.control.contains(e.target)&&!t.dropdown.contains(e.target))switch(e.keyCode){case KEY_RETURN:return void t.onClick(e)}});let o=getDom('<div class="dropdown-input-wrap">');o.appendChild(e),t.dropdown.insertBefore(o,t.dropdown.firstChild)})});